CREATE SCHEMA ERP;
GO
CREATE TABLE ERP.CATEGORIES(CATEGORY_ID INT PRIMARY KEY, CATEGORY_NAME NVARCHAR(100), STATUS NVARCHAR(20));
CREATE TABLE ERP.BRANDS(BRAND_ID INT PRIMARY KEY, BRAND_NAME NVARCHAR(100), STATUS NVARCHAR(20));
CREATE TABLE ERP.CITY_TIER_MASTER(CITY_TIER_ID INT PRIMARY KEY, CITY NVARCHAR(100), TIER INT, TIER_NAME NVARCHAR(20));
CREATE TABLE ERP.MTL_SYSTEM_ITEMS_B(ITEM_ID INT PRIMARY KEY, ITEM_NAME NVARCHAR(200), SKU NVARCHAR(50), CATEGORY_ID INT, BRAND_ID INT, UNIT_COST DECIMAL(15,2), LIST_PRICE DECIMAL(15,2), STATUS NVARCHAR(20));
CREATE TABLE ERP.ADDRESSES(ADDRESS_ID BIGINT PRIMARY KEY, CUSTOMER_ID BIGINT, CITY_TIER_ID INT, STATE NVARCHAR(10), COUNTRY NVARCHAR(50));
CREATE TABLE ERP.OE_ORDER_HEADERS_ALL(ORDER_ID BIGINT PRIMARY KEY, ORDER_NUMBER NVARCHAR(50), CUSTOMER_ID BIGINT, ORDER_DATE DATETIME2, ORDER_STATUS NVARCHAR(30), PAYMENT_METHOD NVARCHAR(30), PAYMENT_STATUS NVARCHAR(20), SUBTOTAL_AMOUNT DECIMAL(15,2), DISCOUNT_AMOUNT DECIMAL(15,2), TAX_AMOUNT DECIMAL(15,2), SHIPPING_AMOUNT DECIMAL(15,2), TOTAL_AMOUNT DECIMAL(15,2), CURRENCY_CODE NVARCHAR(3), SHIPPING_ADDRESS_ID BIGINT, BILLING_ADDRESS_ID BIGINT, PROMISED_DATE DATE, CREATED_DATE DATETIME2, LAST_UPDATE_DATE DATETIME2);
CREATE TABLE ERP.OE_ORDER_LINES_ALL(ORDER_LINE_ID BIGINT PRIMARY KEY, ORDER_ID BIGINT, ITEM_ID INT, QUANTITY INT, UNIT_PRICE DECIMAL(15,2), LINE_AMOUNT DECIMAL(15,2), LINE_STATUS NVARCHAR(20));
GO
